<?php
 namespace WPAICG\Vector\Providers\OpenAI\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_OpenAI_Strategy; use WPAICG\Core\Providers\OpenAI\OpenAIUrlBuilder; use WP_Error; if (!defined('ABSPATH')) { exit; } function delete_index_logic(AIPKit_Vector_OpenAI_Strategy $strategyInstance, string $index_name): bool|WP_Error { if (!$strategyInstance->get_is_connected_status()) { return new WP_Error('not_connected', __('Not connected to OpenAI.', 'gpt3-ai-content-generator')); } $vector_store_id = $index_name; $url_params = [ 'base_url' => $strategyInstance->get_base_url(), 'api_version' => $strategyInstance->get_api_version(), 'vector_store_id' => $vector_store_id ]; $url = OpenAIUrlBuilder::build('vector_stores_id', $url_params); if (is_wp_error($url)) return $url; $response = _request_logic($strategyInstance, 'DELETE', $url); if (is_wp_error($response)) return $response; return isset($response['deleted']) && $response['deleted'] === true; }